Hooks are functions that let you use state and other React features in functional components.

**What are Hooks?**
- Functions that start with "use"
- Can only be called at the top level
- Can only be called from React functions
- Enable state and lifecycle features in functional components

**Why Hooks?**
- Reuse stateful logic between components
- Organize code by feature rather than lifecycle
- No need for class components
- Better code organization

**Rules of Hooks:**
```jsx
// Only call hooks at the top level
function Component() {
  const [count, setCount] = useState(0); // OK

  if (condition) {
    const [name, setName] = useState(''); // WRONG - inside condition
  }

  useEffect(() => { // OK
    // effect
  });
}

// Only call hooks from React functions
function Component() {
  useEffect(() => {}); // OK
}

function regularFunction() {
  useEffect(() => {}); // WRONG - not a React function
}
```

**Built-in Hooks:**
- useState - State management
- useEffect - Side effects
- useContext - Context API
- useReducer - Complex state logic
- useCallback - Memoized callbacks
- useMemo - Memoized values
- useRef - Persistent values
- useLayoutEffect - Synchronous effects

useEffect lets you perform side effects in functional components.

**Basic useEffect:**
```jsx
import { useEffect, useState } from 'react';

function Timer() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    // Runs after every render
    document.title = `Count: ${count}`;
  });

  return <p>Count: {count}</p>;
}
```

**With Dependency Array:**
```jsx
useEffect(() => {
  // Runs only when count changes
  document.title = `Count: ${count}`;
}, [count]);
```

**Empty Dependency Array:**
```jsx
useEffect(() => {
  // Runs only once on mount
  console.log('Component mounted');
}, []);
```

**Cleanup Function:**
```jsx
useEffect(() => {
  const timer = setInterval(() => {
    console.log('Timer tick');
  }, 1000);

  // Cleanup function
  return () => {
    clearInterval(timer);
  };
}, []);
```

**Common Use Cases:**
```jsx
// Data fetching
useEffect(() => {
  fetch('/api/data')
    .then(res => res.json())
    .then(data => setData(data));
}, []);

// Event listeners
useEffect(() => {
  const handleResize = () => setWidth(window.innerWidth);
  window.addEventListener('resize', handleResize);
  return () => window.removeEventListener('resize', handleResize);
}, []);
```

useContext allows you to consume context values without nesting.

**Creating Context:**
```jsx
import { createContext, useContext } from 'react';

const ThemeContext = createContext('light');

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <Toolbar />
    </ThemeContext.Provider>
  );
}
```

**Consuming Context:**
```jsx
function Toolbar() {
  const theme = useContext(ThemeContext);

  return (
    <div className={theme}>
      <ThemedButton />
    </div>
  );
}
```

**Multiple Contexts:**
```jsx
const ThemeContext = createContext('light');
const UserContext = createContext(null);

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <UserContext.Provider value={{ name: 'John' }}>
        <Component />
      </UserContext.Provider>
    </ThemeContext.Provider>
  );
}

function Component() {
  const theme = useContext(ThemeContext);
  const user = useContext(UserContext);

  return <div className={theme}>Hello, {user.name}</div>;
}
```

**Default Values:**
```jsx
const ThemeContext = createContext('light'); // Default value

function Component() {
  const theme = useContext(ThemeContext);
  // Returns 'light' if no provider
}
```

useRef returns a mutable ref object that persists for the lifetime of the component.

**Basic useRef:**
```jsx
import { useRef } from 'react';

function TextInput() {
  const inputRef = useRef(null);

  const focusInput = () => {
    inputRef.current.focus();
  };

  return (
    <div>
      <input ref={inputRef} />
      <button onClick={focusInput}>Focus Input</button>
    </div>
  );
}
```

**Persisting Values:**
```jsx
function Timer() {
  const [count, setCount] = useState(0);
  const timerRef = useRef(null);

  const startTimer = () => {
    timerRef.current = setInterval(() => {
      setCount(c => c + 1);
    }, 1000);
  };

  const stopTimer = () => {
    clearInterval(timerRef.current);
  };

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={startTimer}>Start</button>
      <button onClick={stopTimer}>Stop</button>
    </div>
  );
}
```

**Previous Value:**
```jsx
function Counter() {
  const [count, setCount] = useState(0);
  const prevCountRef = useRef(count);

  useEffect(() => {
    prevCountRef.current = count;
  }, [count]);

  const prevCount = prevCountRef.current;

  return (
    <div>
      <p>Current: {count}</p>
      <p>Previous: {prevCount}</p>
    </div>
  );
}
```

Create your own hooks to reuse stateful logic between components.

**Creating a Custom Hook:**
```jsx
import { useState, useEffect } from 'react';

function useWindowSize() {
  const [size, setSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight
  });

  useEffect(() => {
    const handleResize = () => {
      setSize({
        width: window.innerWidth,
        height: window.innerHeight
      });
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return size;
}
```

**Using Custom Hook:**
```jsx
function Component() {
  const { width, height } = useWindowSize();

  return (
    <div>
      <p>Width: {width}</p>
      <p>Height: {height}</p>
    </div>
  );
}
```

**Another Example - useFetch:**
```jsx
function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch(url)
      .then(res => res.json())
      .then(data => {
        setData(data);
        setLoading(false);
      })
      .catch(err => {
        setError(err);
        setLoading(false);
      });
  }, [url]);

  return { data, loading, error };
}

function Users() {
  const { data, loading, error } = useFetch('/api/users');

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error.message}</p>;

  return <ul>{data.map(user => <li key={user.id}>{user.name}</li>)}</ul>;
}
```
